var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"제발 제 말을 믿어 주세요. 정말 일생일대의 발견이 기다리고 있을 거라니까요.","JPN":"どうか信じてください。本当に一世一代の発見になりますよ。","ENG":"Please believe me. The greatest discovery of our era is waiting for us there.","TWN":"拜託請相信我，你不會吃虧的，這真的是絕無僅有的大發現！"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"그 유적만 찾는다면 현대사회의 패러다임을 바꿀 혁신도 꿈이 아니란 말입니다!","JPN":"あの遺跡さえ見つけ出したら、現代社会のパラダイムを変える革新も夢の話ではありません！","ENG":"If we can find those ruins, we could change the very paradigm of modern society!","TWN":"只要找到那個遺跡，顛覆現在社會模式的革新，就也不再是夢！"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"그렇다면 당신 주장을 믿을 근거를 제시해야 하지 않습니까.","JPN":"ならば、あなたの主張を裏付ける根拠を提示しなければならないでしょう。","ENG":"Then you must present evidence to underpin such claims.","TWN":"那請你提出足以支持你論點的證據。"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"이야기는 장황했지만 결국 유적의 실존 여부를 증명할 수 없다는 의미로 해석되는군요.","JPN":"話が長いだけで、結局遺跡が実在するかどうかを証明できないという意味に解釈されますから。","ENG":"Despite your grandiose words, it seems to me that there is no way to actually prove the existence of such ruins.","TWN":"否則你講那麼多，我也只能解讀為，你無法證明遺跡是否真的存在。"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"굳이 제 사무실에 온 이유도 그 3류 미만의 포트폴리오에 혹한 투자자가 없어서겠죠.","JPN":"わざわざ私の事務所に来た理由も、\\nその三流未満のポートフォリオに惹かれた投資者がいなかったからでしょう。","ENG":"And I'm sure you came to me because you couldn't persuade any investors with your third-rate portfolio.","TWN":"你會找到這裡來，也是因為沒有冤大頭，要投資你那個破爛公事包吧？"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"그, 그걸 어떻게…….","JPN":"ど、どうしてそれを……","ENG":"H-how did you know...","TWN":"唔…要我怎麼證明……"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"실패가 명확한 곳에 투자하는 바보는 찾기 어렵기 때문이죠.","JPN":"失敗が目に見えているところに投資する馬鹿は中々いないでしょう。","ENG":"No one is foolish enough to invest in certain failure, that's why.","TWN":"明知道會虧本的生意，是沒人會做的。"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"대출 상담은 끝났습니다. 더 할 말이 있습니까.","JPN":"ローンの相談は終わりました。他に言いたいことがありますか。","ENG":"This concludes your loan interview. Did you have anything else to say?","TWN":"資金洽談結束，對話到此為。"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"자, 잠깐만 기다려 주세요! 담보도 내놓을 수 있어요!","JPN":"お、お待ちください！　担保があるならどうですか？","ENG":"H-hold up just one minute! I can give you collateral!","TWN":"等…等等！我有東西可以抵押給你們！"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"담보로 잡을 만한 재산이 있었다면 제도권 금융기관에서 해결했겠죠.","JPN":"担保にできそうな財産があるのなら、正規の金融機関で解決できたでしょう。","ENG":"If you really had anything worth holding as collateral, you would have already gone to the banks.","TWN":"如果你有可以抵押的財產，那應該在一般的金融機構，就可以解決你的問題吧？"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"큭…….","JPN":"くっ……","ENG":"Argh…","TWN":"唔……"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"하지만……. 고작 돈 때문에, 이대로 꿈을 포기할 수는…….","JPN":"しかし……金なんかのせいで、このまま夢を諦めるわけには……","ENG":"But… I just can't give up on my dreams over some paltry money…","TWN":"可是我……不想因為錢的問題而放棄夢想……"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"제 사무실에서 꼴값 떨지 마십시오.","JPN":"私の事務所で柄にもない行動はやめてください。","ENG":"Please take your inane drama elsewhere.","TWN":"我們公司不吃苦肉計這套。"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"여기 당신이 부탁한 금액, 전액 현찰입니다.","JPN":"ここにあなたに頼まれた金額、全額現金があります。","ENG":"Here is the amount you requested. In cash.","TWN":"這是你要的金額，全都是現金。"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"네……? 이, 이렇게 많은 돈을 흔쾌히……?","JPN":"え……？　こ、こんな大金を……？","ENG":"What…? Y-you're giving me this much cash… that easily?","TWN":"什麼……？這麼爽快地就把這麼多錢……？"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"알겠습니다! 제 꿈을 이해해 주신 거군요!","JPN":"ああ、僕の夢を理解してくれたのですね！","ENG":"I see! You've finally understood my dream!","TWN":"原來如此！你也認同我的夢想是嗎！"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L23_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"저는 당신의 꿈을 이해한 적도 없고, 이해할 예정도 없습니다.","JPN":"私はあなたの夢を理解したことも、理解するつもりもありません。","ENG":"I have not, nor will ever understand your dream.","TWN":"我沒有認同過你的夢想，也不打算認同。"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L24_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"사채업자로서 대출을 해 줬을 뿐입니다. 사용처를 확인한 이유는 절차이기 때문이죠.","JPN":"闇金業者として金を貸しただけです。使用目的を確かめた理由はただの手続きに過ぎません。","ENG":"I've simply given you a loan, per my profession. Checking the purpose of the loan was merely to fulfill due process.","TWN":"我借你這些錢，只是因為我是放高利貸的，問你用途也只是基於流程而已。"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_PRIDE"}}}}]`);export{e as default};